const src = $input.all()[0];
// ── Deduplication guard ─────────────────────────────────────────────────────
const messageId = (src.json && src.json.message && src.json.message.message_id)
    ? String(src.json.message.message_id)
    : null;


// Detect trigger source by inspecting the item shape.
let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.chat) {
    // Telegram trigger
    task = 'user_dm';
    let _utext = src.json.message.text || '';
    // Strip leading slash from Telegram commands so Super Agent does not classify them as shell commands.
    if (_utext.startsWith('/')) {
        const parts = _utext.slice(1).split(/\s+/);
        const cmd = (parts[0] || '').toLowerCase();
        const rest = parts.slice(1).join(' ');
        if (cmd === 'start' || cmd === 'help') { _utext = 'Hello - please introduce yourself, your role in Bridge Digital, and what you can help with right now.'; }
        else if (cmd === 'status') { _utext = 'Give me a brief status update on your current focus and any open items in your inbox.'; }
        else { _utext = (cmd + ' ' + rest).trim(); }
    }
    user_text = _utext;
    chat_id = src.json.message.chat.id;
    from_agent = 'user';
} else if (src.json && src.json.body && src.json.body.task) {
    // Webhook trigger
    task = src.json.body.task;
    user_text = src.json.body.message || null;
    from_agent = src.json.body.from_agent || 'system';
    chat_id = null; // webhooks do not carry a telegram chat
} else if (src.json && src.json.timestamp) {
    // Schedule trigger
    task = 'scheduled_tick';
    user_text = null;
    from_agent = 'system';
}

return [{ json: { message_id: messageId,
    bot_name: "programmer",
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso: new Date().toISOString(),
    daily_spec: [{"hour": 10, "minute": 0, "task_name": "daily_build_pulse"}],
    weekly_spec: [{"weekday": 1, "hour": 15, "minute": 0, "task_name": "weekly_engineering_review"}],
} }];

const raw = $json.response || '';
const defaultRisk = 'high';
const riskMap = {"memo": "low", "archive": "low", "no_op": "low", "escalate": "low", "query": "medium", "cleanup": "high"};

let parsed = null;
let parseError = null;
try {
    let cleaned = raw.trim().replace(/^```(?:json)?/, '').replace(/```$/, '').trim();
    parsed = JSON.parse(cleaned);
} catch (e) { parseError = e.message; }
if (!parsed) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch (e) {} }

let reply_text = '';
if (parsed && typeof parsed === 'object') {
    reply_text = typeof parsed.reply_text === 'string' ? parsed.reply_text : '';
} else {
    reply_text = String(raw || '').trim().slice(0, 3500) || 'I am online but had no response to share. Please try a more specific question.';
    parsed = { actions: [] };
}
const actions = Array.isArray(parsed.actions) ? parsed.actions.slice(0, 5) : [];

// SECURITY GATE: intercept executable actions, reroute to security if no SAFE review exists
const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
function hasSafeReview(implId) {
    if (!implId) return false;
    return inbox.some(m => m && m.from_agent === 'security' && m.memo_type === 'security_review'
                            && m.body_json && m.body_json.implementation_id === implId
                            && m.body_json.status === 'SAFE');
}
function isExecutableAction(a) {
    if (!a || typeof a !== 'object') return false;
    if (a.type === 'cleanup') return true;
    if (a.type === 'escalate') return true;
    if (a.type === 'query' && a.payload && a.payload.sql && /\b(insert|update|delete|drop|truncate|alter|create)\b/i.test(a.payload.sql)) return true;
    return false;
}
const reroutedActions = actions.map(a => {
    if (!isExecutableAction(a)) return a;
    const subject = (a.payload && a.payload.subject) || ('exec_' + a.type);
    const implId = (a.payload && a.payload.body_json && a.payload.body_json.implementation_id) || subject;
    if (hasSafeReview(implId)) return a;
    return {
        type: 'memo',
        payload: {
            to_agent: 'security',
            memo_type: 'security_review_request',
            priority: 'high',
            subject: 'Security review needed: ' + subject,
            body_json: {
                implementation_id: implId,
                task: subject,
                code_or_logic: (a.payload && (a.payload.sql || a.payload.body_json || a.payload)) || {},
                deferred_action: a,
                deferred_reason: 'Programmer security gate: no resolved SAFE review for this implementation',
                submitted_at: new Date().toISOString()
            }
        }
    };
});

const annotated = reroutedActions.map(a => {
    const type = (a && typeof a.type === 'string') ? a.type : 'no_op';
    const risk = riskMap[type] || defaultRisk;
    return { type, risk, payload: a.payload || {} };
});

// Pull forward context we need downstream.
const upstream = $('Assemble prompt').first().json;

return [{ json: {
    reply_text,
    actions: annotated,
    bot_name: upstream.bot_name,
    user_chat_id: upstream.user_chat_id,
    task_kind: upstream.task_kind,
    model_used: $json.model_used || 'unknown',
} }];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

